changeSet.sql:
-- Add system module URLs INSERT INTO clinlims.system_module_url(id, system_module_id, url_path) VALUES ( (SELECT MAX(id) + 1 FROM clinlims.system_module_url), (SELECT id FROM clinlims.system_module WHERE name = 'BacteriologyClassicReports'), '/BacteriologyReports' );
INSERT INTO clinlims.system_module_url(id, system_module_id, url_path) VALUES ( (SELECT MAX(id) + 1 FROM clinlims.system_module_url), (SELECT id FROM clinlims.system_module WHERE name = 'BacteriologyClassicReports'), '/BacteriologyReport' );
-- Grant to Reports role INSERT INTO clinlims.system_role_module(id, system_role_id, system_module_id, has_select, has_add, has_update, has_delete) SELECT (SELECT MAX(id) + 1 FROM clinlims.system_role_module), (SELECT id FROM clinlims.system_role WHERE name = 'Reports'), (SELECT id FROM clinlims.system_module WHERE name = 'BacteriologyClassicReports'), 'Y', 'N', 'N', 'N' WHERE NOT EXISTS ( SELECT 1 FROM clinlims.system_role_module WHERE system_role_id = (SELECT id FROM clinlims.system_role WHERE name = 'Reports') AND system_module_id = (SELECT id FROM clinlims.system_module WHERE name = 'BacteriologyClassicReports') );
-- Grant to Results role INSERT INTO clinlims.system_role_module(id, system_role_id, system_module_id, has_select, has_add, has_update, has_delete) SELECT (SELECT MAX(id) + 1 FROM clinlims.system_role_module), (SELECT id FROM clinlims.system_role WHERE name = 'Results'), (SELECT id FROM clinlims.system_module WHERE name = 'BacteriologyClassicReports'), 'Y', 'N', 'N', 'N' WHERE NOT EXISTS ( SELECT 1 FROM clinlims.system_role_module WHERE system_role_id = (SELECT id FROM clinlims.system_role WHERE name = 'Results') AND system_module_id = (SELECT id FROM clinlims.system_module WHERE name = 'BacteriologyClassicReports') );
